import React, { useEffect, useState } from "react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  Legend,
  LineChart,
  Line,
  ResponsiveContainer,
} from "recharts";
import "../styles/MoodTracker.css";

const moodColors = {
  happy: "#22c55e",
  neutral: "#3b82f6",
  sad: "#ef4444",
  anxious: "#f97316",
};

const MoodTracker = () => {
  const [moods, setMoods] = useState([]);
  const [showGraph, setShowGraph] = useState(false);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("moodHistory")) || [];
    setMoods(stored);
  }, []);

  // COUNT MOODS
  const moodCount = moods.reduce((acc, curr) => {
    acc[curr.mood] = (acc[curr.mood] || 0) + 1;
    return acc;
  }, {});

  // BAR GRAPH DATA
  const barData = Object.keys(moodCount).map((mood) => ({
    mood,
    count: moodCount[mood],
    fill: moodColors[mood],
  }));

  // LINE GRAPH DATA
  const lineData = moods.map((entry, index) => ({
    index: index + 1,
    happy: entry.mood === "happy" ? 5 : null,
    neutral: entry.mood === "neutral" ? 3 : null,
    sad: entry.mood === "sad" ? 1 : null,
    anxious: entry.mood === "anxious" ? 2 : null,
  }));

  return (
    <div className="mood-page">
      <h2>🧠 Mood Tracker</h2>

      {/* TEXT SUMMARY */}
      <div className="mood-summary">
        <p>😊 Happy: {moodCount.happy || 0} times</p>
        <p>😐 Neutral: {moodCount.neutral || 0} times</p>
        <p>😔 Sad: {moodCount.sad || 0} times</p>
        <p>😟 Anxious: {moodCount.anxious || 0} times</p>
      </div>

      <p className="mood-insight">
        {moodCount.neutral > moodCount.happy
          ? "You were mostly neutral recently. That’s okay — awareness is the first step 💙"
          : "You’ve had some positive moments lately 🌱 Keep going!"}
      </p>

      {/* BUTTON */}
      <button className="graph-btn" onClick={() => setShowGraph(!showGraph)}>
        📊 {showGraph ? "Hide Graphs" : "Show Mood Graphs"}
      </button>

      {/* GRAPHS */}
      {showGraph && (
        <>
          {/* BAR GRAPH */}
          <h3>Mood Frequency</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={barData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="mood" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="count" />
            </BarChart>
          </ResponsiveContainer>

          {/* LINE GRAPH */}
          <h3>Mood Journey</h3>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={lineData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="index" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="happy" stroke={moodColors.happy} />
              <Line type="monotone" dataKey="neutral" stroke={moodColors.neutral} />
              <Line type="monotone" dataKey="sad" stroke={moodColors.sad} />
              <Line type="monotone" dataKey="anxious" stroke={moodColors.anxious} />
            </LineChart>
          </ResponsiveContainer>
        </>
      )}
    </div>
  );
};

export default MoodTracker;
